      {'e': 'workforce', 'c': '劳动力', 'p': '/ˈwɜːkfɔːs/', 'd': 'skilled workforce 熟练劳动力', 'ex': 'The company has a skilled workforce.', 'ex_cn': '公司拥有一支熟练的劳动力队伍。'},
    ];

	    return data.map((e) => Word(
	      english: e['e']!,
	      chinese: e['c']!,
	      pronunciation: e['p'],
	      example: e['ex'],
	      exampleChinese: e['ex_cn'],
	      detailExplanation: e['d'],
	      level: 'senior',
	    )).toList();
  }

  static List<Word> getAllWords() {
    return [...getJuniorWords(), ...getSeniorWords()];
  }
